agent_output:
{
  "executive_summary": "Architecture for a real-time ML delivery time estimation service with a clear separation between the serving path (latency-critical, called at checkout) and the training path (batch, weekly). The design optimizes for the 100ms P99 constraint by pre-computing features and serving predictions via an in-process model rather than a remote inference service. A blue-green model deployment strategy enables instant rollback. Scoped for a 4-person team — avoids Kubernetes/Kubeflow complexity in favor of simpler, proven infrastructure.",

  "architecture": {
    "components": [
      {
        "name": "Prediction Service",
        "responsibility": "Serves real-time delivery time predictions. Loads the model into process memory (ONNX Runtime or similar). Receives feature vectors, runs inference, returns predicted minutes. Stateless — horizontally scalable.",
        "boundaries": "Owns only inference. No training logic. No raw data access. Receives pre-computed or on-the-fly features from the Feature Service."
      },
      {
        "name": "Feature Service",
        "responsibility": "Computes the feature vector from raw inputs (weight, distance, zone, time_of_day, weather, courier_load). Splits into two paths: (1) real-time features computed on request (time_of_day, weather from cache, courier_load from cache), (2) pre-computed features looked up from Feature Store (zone historical averages, courier reliability scores).",
        "boundaries": "Owns feature computation logic and feature schema. Does not own raw data ingestion or model inference."
      },
      {
        "name": "Feature Store",
        "responsibility": "Stores pre-computed features (zone stats, courier stats, historical patterns). Backed by Redis for online serving, with a batch pipeline writing to it from the data warehouse. Ensures training and serving use identical feature definitions (training-serving skew prevention).",
        "boundaries": "Owns feature persistence and versioning. Does not own feature computation logic — that lives in shared feature definitions used by both the Feature Service and Training Pipeline."
      },
      {
        "name": "Training Pipeline",
        "responsibility": "Weekly batch job. Pulls historical delivery data + features from the data warehouse, trains the model (gradient-boosted trees via XGBoost/LightGBM), evaluates against holdout set and the currently-live model, publishes the candidate model to the Model Registry if quality gates pass.",
        "boundaries": "Owns model training, hyperparameter tuning, and offline evaluation. Runs in isolation — no impact on serving path. Writes only to Model Registry and metrics store."
      },
      {
        "name": "Model Registry",
        "responsibility": "Versioned storage of trained model artifacts (model binary, metadata, training metrics, feature schema version). Tracks which version is 'live', 'candidate', and 'previous'. Supports instant rollback by pointer swap.",
        "boundaries": "Owns model artifact lifecycle. Does not decide which model to promote — that's the Deployment Controller's job."
      },
      {
        "name": "Deployment Controller",
        "responsibility": "Orchestrates blue-green model deployment. On new candidate: (1) deploys to canary instances, (2) monitors live metrics (prediction error, latency, error rate) for a soak period, (3) promotes to full fleet or rolls back. Rollback is a pointer swap in the Model Registry + signal to Prediction Service instances to reload.",
        "boundaries": "Owns promotion/rollback decisions. Does not own training or serving — only the deployment transition."
      },
      {
        "name": "Data Pipeline",
        "responsibility": "Ingests completed delivery records (actual delivery times) into the data warehouse. Joins with order data and feature snapshots to create labeled training data. Runs daily.",
        "boundaries": "Owns data ingestion and training dataset creation. Reads from operational databases, writes to data warehouse."
      },
      {
        "name": "Monitoring & Observability",
        "responsibility": "Tracks prediction accuracy (predicted vs actual delivery time), feature drift, model latency P50/P95/P99, error rates. Alerts on degradation. Feeds dashboards for the team.",
        "boundaries": "Read-only. Consumes logs and metrics from all other components. Triggers alerts but does not take automated action (Deployment Controller handles rollback)."
      }
    ],
    "interfaces": [
      {
        "from": "Checkout API",
        "to": "Prediction Service",
        "contract": "POST /predict { weight_kg: float, distance_km: float, zone_id: string, weather_code: string, courier_load: int } → { estimated_minutes: int, confidence_interval: [int, int], model_version: string }",
        "coupling_type": "synchronous REST — latency-critical path"
      },
      {
        "from": "Prediction Service",
        "to": "Feature Service",
        "contract": "In-process call or co-located sidecar. get_features(raw_input) → FeatureVector. Must complete in <10ms to leave 90ms budget for inference.",
        "coupling_type": "tight — co-located for latency"
      },
      {
        "from": "Feature Service",
        "to": "Feature Store",
        "contract": "Redis GET by composite key (zone_id, time_bucket). Returns pre-computed feature values. <5ms P99.",
        "coupling_type": "loose — cache lookup with fallback defaults"
      },
      {
        "from": "Training Pipeline",
        "to": "Model Registry",
        "contract": "publish_model(artifact, metrics, feature_schema_version) → model_version_id",
        "coupling_type": "asynchronous — batch job publishes after training completes"
      },
      {
        "from": "Deployment Controller",
        "to": "Model Registry",
        "contract": "promote(version_id) / rollback() — swaps the 'live' pointer",
        "coupling_type": "loose — control plane operation"
      },
      {
        "from": "Deployment Controller",
        "to": "Prediction Service",
        "contract": "Signal (file watch, config reload endpoint, or pub/sub) to hot-reload model from registry. No restart required.",
        "coupling_type": "loose — async signal, service pulls new model"
      },
      {
        "from": "Data Pipeline",
        "to": "Training Pipeline",
        "contract": "Writes labeled dataset to data warehouse (S3/BigQuery). Training Pipeline reads from known table/path with schema contract.",
        "coupling_type": "loose — shared storage, schema-versioned"
      }
    ],
    "data_flow": "SERVING PATH: Checkout API → Prediction Service → Feature Service (computes real-time features + lookups from Feature Store/Redis) → Model inference (in-process ONNX/LightGBM) → Response with estimated_minutes + model_version. Total budget: 100ms P99. TRAINING PATH: Completed deliveries → Data Pipeline (daily) → Data Warehouse → Training Pipeline (weekly) → Model Registry → Deployment Controller (canary + promote/rollback) → Prediction Service hot-reloads new model. FEEDBACK LOOP: Prediction Service logs (prediction, model_version, request_id) → after delivery completes, Data Pipeline joins actual time → training dataset for next cycle.",
    "patterns_used": [
      {
        "pattern": "In-process model serving (embedded inference)",
        "rationale": "The 100ms P99 constraint eliminates remote inference services (TensorFlow Serving, SageMaker endpoints) which add network hops. Loading the model directly into the Prediction Service process via ONNX Runtime or native LightGBM gives sub-10ms inference for tabular models. This is the single most important architectural decision."
      },
      {
        "pattern": "Blue-Green Model Deployment",
        "rationale": "Business requirement for instant rollback. Two model slots (live + previous) in the Model Registry. Rollback is a pointer swap + reload signal. No redeployment needed."
      },
      {
        "pattern": "Feature Store (online + offline)",
        "rationale": "Prevents training-serving skew — the #1 silent killer of ML systems. Shared feature definitions ensure the model sees the same features in training and serving. Redis for online (<5ms), warehouse tables for offline training."
      },
      {
        "pattern": "Canary Deployment with Automated Soak",
        "rationale": "Catches model degradation before full rollout. Route 5-10% of traffic to new model, compare prediction accuracy and latency against baseline for 2-4 hours, then auto-promote or auto-rollback."
      },
      {
        "pattern": "Shadow Scoring (optional, phase 2)",
        "rationale": "Run new model in parallel without serving its results. Compare offline. Adds safety for high-risk model changes without user impact."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Prediction Serving",
        "classification": "core",
        "aggregates": ["PredictionRequest (value object: features + metadata)", "PredictionResponse (value object: estimated_minutes, confidence, model_version)"]
      },
      {
        "name": "Feature Engineering",
        "classification": "core",
        "aggregates": ["FeatureDefinition (entity: name, version, computation logic)", "FeatureVector (value object: computed features for a single request)"]
      },
      {
        "name": "Model Lifecycle",
        "classification": "core",
        "aggregates": ["ModelVersion (entity: artifact, metrics, status, feature_schema_version)", "DeploymentState (entity: live_version, previous_version, canary_version)"]
      },
      {
        "name": "Training",
        "classification": "supporting",
        "aggregates": ["TrainingJob (entity: dataset_ref, hyperparameters, status, output_model_version)", "TrainingDataset (value object: warehouse path, schema version, row count, date range)"]
      },
      {
        "name": "Data Ingestion",
        "classification": "generic",
        "aggregates": ["DeliveryRecord (entity: order_id, predicted_time, actual_time, features_snapshot)"]
      }
    ],
    "context_map": [
      {
        "upstream": "Feature Engineering",
        "downstream": "Prediction Serving",
        "relationship": "Open Host Service — Feature Service exposes a stable API for feature vector computation"
      },
      {
        "upstream": "Feature Engineering",
        "downstream": "Training",
        "relationship": "Shared Kernel — feature definitions are shared code to prevent training-serving skew"
      },
      {
        "upstream": "Model Lifecycle",
        "downstream": "Prediction Serving",
        "relationship": "Customer-Supplier — Model Lifecycle publishes models, Prediction Serving consumes them via hot-reload"
      },
      {
        "upstream": "Data Ingestion",
        "downstream": "Training",
        "relationship": "Conformist — Training consumes the data schema defined by ingestion"
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "In-process model serving instead of dedicated inference service (TF Serving, Triton, SageMaker)",
      "gains": "Sub-10ms inference latency for tabular models. No network hop. Simpler infrastructure — no separate model serving cluster to manage. Perfect for a 4-person team.",
      "sacrifices": "Prediction Service must handle model loading/reloading. Memory footprint increases per instance. If the team later needs GPU inference (deep learning models), this pattern breaks.",
      "alternatives_considered": ["TensorFlow Serving / Triton — adds 10-30ms network latency, overkill for tabular models", "SageMaker endpoints — managed but adds vendor lock-in, latency, and cost"]
    },
    {
      "decision": "LightGBM/XGBoost (gradient-boosted trees) instead of deep learning",
      "gains": "Fast inference (<5ms on CPU). Interpretable. Trains in minutes, not hours. Excellent for tabular data with <20 features. Well within 100ms P99 budget.",
      "sacrifices": "Cannot capture complex non-linear feature interactions as well as deep models. If the feature space grows dramatically (e.g., adding courier trajectory data), may need to revisit.",
      "alternatives_considered": ["Neural network — higher latency, harder to train weekly, no significant accuracy gain on tabular data per benchmarks", "Linear regression — too simple, won't capture zone/weather/load interactions"]
    },
    {
      "decision": "Redis-backed Feature Store instead of a full-featured platform (Feast, Tecton)",
      "gains": "Simple. The team already needs Redis. 4 engineers cannot justify operating Feast infrastructure. Pre-computed features in Redis are sub-5ms lookups.",
      "sacrifices": "No built-in feature versioning UI, lineage tracking, or point-in-time joins out of the box. Team must build lightweight versioning themselves.",
      "alternatives_considered": ["Feast — good OSS option but operational overhead for 4 people", "Tecton — excellent but expensive and overkill at this scale"]
    },
    {
      "decision": "Canary deployment with metric-based promotion instead of A/B testing framework",
      "gains": "Simpler to implement. Sufficient for weekly model updates. Catches regressions before full rollout.",
      "sacrifices": "Not statistically rigorous for measuring small accuracy improvements. If the team wants to compare two fundamentally different model architectures, they'll need proper A/B testing later.",
      "alternatives_considered": ["Full A/B testing platform — too complex for 4 engineers and weekly releases", "No canary (just swap) — too risky given checkout-path criticality"]
    }
  ],

  "flexibility_points": [
    {
      "area": "Model algorithm",
      "evolution_path": "The Prediction Service loads any ONNX-compatible model. Swapping from LightGBM to XGBoost to a neural network requires only re-exporting to ONNX format. No serving code changes."
    },
    {
      "area": "Feature set",
      "evolution_path": "Adding new features means: (1) add feature definition to shared library, (2) add computation to Feature Service, (3) retrain. The serving infrastructure doesn't change. Feature schema is versioned so old models still work with old schemas during transition."
    },
    {
      "area": "Retraining frequency",
      "evolution_path": "Moving from weekly to daily retraining is a cron schedule change + ensuring the data pipeline runs daily (it already does). No architectural changes needed."
    },
    {
      "area": "Scaling the serving tier",
      "evolution_path": "Prediction Service is stateless — add more instances behind a load balancer. Model is loaded in-process so each instance is independent."
    }
  ],

  "rigidity_points": [
    {
      "area": "Feature schema contract between training and serving",
      "reason": "Intentionally rigid. Training-serving skew is the most common ML system failure mode. The shared feature definition library is a Shared Kernel — changes require coordinated updates to both training and serving. This coupling is protective."
    },
    {
      "area": "In-process serving constraint",
      "reason": "Locks the team into CPU-friendly models. If a future model requires GPU inference, the architecture must change to remote serving. Acceptable trade-off given the current problem (tabular data, <20 features)."
    },
    {
      "area": "100ms P99 latency budget",
      "reason": "This is a hard constraint from the business (checkout path). Every component in the serving path must be designed around this. Adding external service calls to the hot path is not allowed without re-evaluating the budget."
    }
  ],

  "risks": [
    {
      "risk": "Training-serving skew: features computed differently in training vs serving leads to silent accuracy degradation",
      "severity": "critical",
      "mitigation": "Shared feature definition library used by both Feature Service and Training Pipeline. Integration tests that compute features for known inputs and assert identical outputs in both paths. Log feature vectors at serving time and compare distributions against training data."
    },
    {
      "risk": "Model degradation goes undetected: new model is worse but passes quality gates",
      "severity": "high",
      "mitigation": "Canary deployment with real-time comparison of prediction error (predicted vs actual, measured after delivery completes). Automated rollback if error exceeds threshold. Additionally, monitor for distribution shift in input features (data drift)."
    },
    {
      "risk": "Cold start latency: model loading on Prediction Service startup exceeds acceptable time",
      "severity": "medium",
      "mitigation": "LightGBM/ONNX models for tabular data are typically <100MB and load in <1 second. Use readiness probes — don't route traffic until model is loaded. Pre-warm instances before draining old ones."
    },
    {
      "risk": "Feature Store (Redis) unavailability degrades predictions",
      "severity": "high",
      "mitigation": "Feature Service must have sensible defaults/fallbacks for pre-computed features (e.g., zone-level averages cached locally with a 1-hour TTL). Degrade gracefully — a slightly less accurate prediction is better than a checkout failure."
    },
    {
      "risk": "4-person team spread too thin across ML + platform concerns",
      "severity": "medium",
      "mitigation": "Phase the build. Phase 1 (weeks 1-3): Prediction Service + simple feature computation + manual model deployment. Phase 2 (weeks 4-6): Feature Store + Training Pipeline automation. Phase 3 (weeks 7-8): Canary deployment + monitoring. Ship value incrementally."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1: Build the Prediction Service with in-process LightGBM model, a simple Feature Service (compute all features on the fly, no Feature Store yet), and a manual model deployment process (upload model artifact, restart service). This gets a working system into production in 2-3 weeks. Phase 2: Add the Feature Store (Redis), the automated Training Pipeline, and the Model Registry. Phase 3: Add the Deployment Controller with canary and auto-rollback. Team split: 2 ML engineers own Training Pipeline + Feature Engineering + model development. 2 platform engineers own Prediction Service + Feature Store + Deployment Controller + Monitoring.",
    "files_to_create_or_modify": [
      "services/prediction-service/ — Go or Rust for latency-critical serving (or Python with ONNX Runtime if team is Python-heavy)",
      "libs/feature-definitions/ — Shared Python library defining feature computation (used by both serving and training)",
      "pipelines/training/ — Python, orchestrated by Airflow or a simple cron + script",
      "pipelines/data-ingestion/ — ETL job writing completed deliveries to warehouse",
      "infra/model-registry/ — S3 bucket + DynamoDB/Postgres metadata table (or MLflow if team prefers)",
      "services/deployment-controller/ — Script or small service managing canary promotion",
      "monitoring/dashboards/ — Grafana dashboards for prediction accuracy, latency, drift"
    ],
    "patterns_to_follow": "Twelve-Factor App for the Prediction Service (config via env vars, stateless processes, disposability). Feature definitions as a versioned shared library with semantic versioning. Model artifacts stored immutably — never overwrite, always create new versions. Every prediction logged with model_version and request_id for downstream accuracy measurement.",
    "pitfalls_to_avoid": [
      "Do NOT call an external ML inference service in the hot path — the 100ms budget won't survive the network hop under load",
      "Do NOT compute features differently in training vs serving — this is the #1 cause of ML system failures",
      "Do NOT skip the feedback loop — you must join predictions with actual delivery times to measure accuracy and generate training data",
      "Do NOT deploy a new model without comparing it against the live model on a holdout set AND in canary — offline metrics lie",
      "Do NOT build a custom ML platform — use simple tools (cron, S3, Redis, Postgres) that the 4-person team can actually operate",
      "Do NOT use Python for the hot serving path if latency is tight — ONNX Runtime in Go/Rust or at minimum a uvicorn/FastAPI service with ONNX is much faster than loading sklearn/LightGBM natively in a request handler"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 88,
    "high_confidence_areas": [
      "In-process model serving is the correct pattern for 100ms P99 on tabular data — this is well-established",
      "LightGBM/XGBoost is the right model family for this feature set and latency budget",
      "Blue-green model deployment with pointer swap handles the rollback requirement cleanly",
      "Feature Store with shared definitions prevents training-serving skew",
      "Phased implementation is essential for a 4-person team"
    ],
    "low_confidence_areas": [
      "Exact latency budget allocation (feature computation vs inference vs serialization) — needs profiling with real data",
      "Whether the team is Python-heavy or has Go/Rust capability — affects Prediction Service implementation language choice",
      "Volume of requests at checkout — if it's >10K RPS, need to validate horizontal scaling assumptions"
    ],
    "assumptions": [
      "Request volume is moderate (hundreds to low-thousands RPS, not tens of thousands)",
      "The feature set is tabular with <20 features — no unstructured data (images, text)",
      "The team has Python ML experience and can operate basic infrastructure (Redis, S3, Postgres)",
      "Weather data is available via an external API or cached feed — not something the team builds",
      "Courier load data is available in near-real-time from the operational system"
    ]
  }
}
